var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"드디어 정신이 드냐? 미나토?","JPN":"やっと目が覚めたか？　湊？","ENG":"Finally awake, Minato?","TWN":"你終於醒啦？南裕夏？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키…? 너 괜찮은 거야?","JPN":"雅紀……？　お前平気なの？","ENG":"Masaki...? You good?","TWN":"雅紀……？你沒事吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"네 꼴을 봐라. 걱정은 내가 해야지.","JPN":"お前の格好を見ろよ。オレの方が心配したぞ。","ENG":"Say for yourself. You look worse than me.","TWN":"你看看你，該擔心的人是我吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나야 금방 회복했지만……","JPN":"オレはすぐ回復したけど……","ENG":"I mean, I recovered pretty quickly, but...","TWN":"我是恢復得很快……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"넌 카운터가 아니었으면 수술도 못 받았을 거래.","JPN":"お前はカウンターじゃなかったら手術もできなかったってよ。","ENG":"The docs told me that you would've never survived the surgery if you weren't a Counter.","TWN":"但醫生說要不是你是制裁者，恐怕連手術都沒辦法做。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…그 정도야?","JPN":"……そんなに？","ENG":"Was it that bad?","TWN":"……那麼嚴重喔？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래도 의사가 이제 잘 먹고 잘 쉬기만 하면 된다니까.","JPN":"でも医者がよく食べてよく寝たら治るって言ってた。","ENG":"But now, they say you'll be fine if you eat up and rest.","TWN":"不過醫生說你現在只要好好吃飯、好好休息就好。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"일단 이거라도 먹을래?","JPN":"まずはこれでも食っとくか？","ENG":"So, you wanna eat this or what?","TWN":"你要吃這個嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"사과? 토끼 모양이네.","JPN":"リンゴ？　うさぎの形だね。","ENG":"An apple? And it's in the shape of a rabbit.","TWN":"蘋果？還是兔子形狀欸。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"큭큭, 예쁘지? 사나에 씨가 깎아주고 간 거야.","JPN":"くく、可愛いだろう？　早苗さんが切ってくれたんだ。","ENG":"Haha, pretty, no? Sanae cut them like that for me.","TWN":"呵呵，很漂亮吧？是早苗削的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그 사람. 나이프 다루는 솜씨가 장난 아니더라.","JPN":"あの人。ナイフを扱うの上手だったな。","ENG":"You should've seen how skillful she was with a knife.","TWN":"她的刀工真的超強的。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"분명 집안일도 엄청 소질있고 가정적이겠지?","JPN":"きっと家事もできて、家庭的なんだろうな？","ENG":"I bet she's also really kind and good at housework too. Ha ha.","TWN":"她一定很會做家事，會是個賢妻良母吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이거 엄청 맛있네요.","JPN":"これ本当に美味しいですね。","ENG":"It's delicious too.","TWN":"這個好好吃喔。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"얌마! 넌 그만 먹어! 사나에 씨가 나한테 준 거라고!","JPN":"おい！　お前は食うなよ！　早苗さんがオレにくれたんだ！","ENG":"Hey! Stop eating that! She left them for me!","TWN":"喂！你別再吃啦！那是早苗給我的！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"싫어요! 약속한 돈이나 내놔요! 이 사기꾼!","JPN":"嫌です！　約束したお金を出しなさい！　この詐欺師！","ENG":"No! Give me my money, you scammer!","TWN":"不要！你先把說好的錢付清吧！你這個騙子！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……사나에 씨가 다녀갔어?","JPN":"……早苗さんが来てたの？","ENG":"...Sanae came by?","TWN":"……早苗來過嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아, 당주님 동생도 너 수술 끝날 때까지 기다리고 있었어.","JPN":"あ、当主の妹もお前の手術が終わるまで待ってたぞ。","ENG":"Oh, even Lady Nanahara's sister waited until your surgery was done.","TWN":"對了，堂主的妹妹也一直等到你手術結束。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};